function ComboKillConfig:initConfig(config)
    self:init(config)
end

function ComboKillConfig:init(config)
    for index, combo in pairs(config) do
        local item = {}
        item.id = tonumber(combo.id)
        item.sound = tonumber(combo.soundType)
        item.icon = combo.icon
        self.combo[index] = item
    end
end

function ComboKillConfig:getInfoById(id)
